using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ───────────────────────────────────────────────────────────
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ── Shared state for the note-taking tool ───────────────────────────────────
var notes = new List<string>();

// ── Build the chat client with automatic function invocation ────────────────
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// ── Define tools ────────────────────────────────────────────────────────────
var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("Mozilla/5.0 (compatible; ResearchAgent/1.0)");
httpClient.Timeout = TimeSpan.FromSeconds(15);

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(SearchWebAsync, "SearchWeb",
            "Searches the web for a query and returns the top results with titles and snippets."),
        AIFunctionFactory.Create(SaveNote, "SaveNote",
            "Saves an important research finding as a note for later reference."),
        AIFunctionFactory.Create(GetNotes, "GetNotes",
            "Retrieves all research notes collected so far."),
    ],
    Temperature = 0.7f,
};

// ── System prompt ───────────────────────────────────────────────────────────
const string SystemPrompt = """
    You are a meticulous research agent. When given a topic you MUST:

    1. Search the web at least 3 times with varied queries to gather broad coverage.
    2. After each search, call SaveNote with the most important facts you discovered.
    3. Once you have gathered enough material, call GetNotes, then write a
       well-structured summary with sections and key takeaways, citing the facts
       you collected.

    Be thorough but concise. Think step-by-step.
    """;

// ── Interactive loop ────────────────────────────────────────────────────────
Console.WriteLine("╔═══════════════════════════════════════╗");
Console.WriteLine("║       🔬  AI Research Agent  🔬      ║");
Console.WriteLine("╠═══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research.           ║");
Console.WriteLine("║  Type 'exit' to quit.                 ║");
Console.WriteLine("╚═══════════════════════════════════════╝");

while (true)
{
    Console.Write("\nTopic > ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("exit", StringComparison.OrdinalIgnoreCase))
        break;

    notes.Clear();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, SystemPrompt),
        new(ChatRole.User, $"Research the following topic and provide a comprehensive summary:\n\n{topic}"),
    };

    Console.WriteLine($"\n🔍 Researching \"{topic}\"…\n");

    try
    {
        var response = await chatClient.GetResponseAsync(messages, chatOptions);

        Console.WriteLine("\n═══════════════════════════════════════");
        Console.WriteLine("📋  RESEARCH SUMMARY");
        Console.WriteLine("═══════════════════════════════════════\n");
        Console.WriteLine(response.Text);
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\n❌ Error: {ex.Message}");
    }
}

Console.WriteLine("\nGoodbye!");

// ── Tool implementations ────────────────────────────────────────────────────

async Task<string> SearchWebAsync(
    [Description("The search query string")] string query)
{
    Console.WriteLine($"  🌐  Searching: \"{query}\"");

    try
    {
        var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
        var html = await httpClient.GetStringAsync(url);
        var results = ExtractSearchResults(html);

        if (results.Count == 0)
            return "No results found. Try a different query.";

        return string.Join("\n\n", results.Select((r, i) =>
            $"[{i + 1}] {r.Title}\n    {r.Snippet}"));
    }
    catch (Exception ex)
    {
        return $"Search failed ({ex.Message}). Try rephrasing the query.";
    }
}

string SaveNote(
    [Description("The note content to save")] string content)
{
    notes.Add(content);
    Console.WriteLine($"  📝  Note saved  (total: {notes.Count})");
    return $"Saved. You now have {notes.Count} note(s).";
}

string GetNotes()
{
    if (notes.Count == 0)
        return "No notes yet. Search and save findings first.";

    Console.WriteLine($"  📖  Retrieving {notes.Count} note(s)");
    return string.Join("\n---\n",
        notes.Select((n, i) => $"Note {i + 1}:\n{n}"));
}

// ── HTML parsing helpers ────────────────────────────────────────────────────

static List<SearchResult> ExtractSearchResults(string html)
{
    var results = new List<SearchResult>();

    var titles = TitleRegex().Matches(html);
    var snippets = SnippetRegex().Matches(html);
    var count = Math.Min(titles.Count, snippets.Count);

    for (var i = 0; i < Math.Min(count, 6); i++)
    {
        var title = StripHtml(titles[i].Groups[1].Value);
        var snippet = StripHtml(snippets[i].Groups[1].Value);
        if (!string.IsNullOrWhiteSpace(title))
            results.Add(new SearchResult(title, snippet));
    }

    return results;
}

static string StripHtml(string s) =>
    WebUtility.HtmlDecode(HtmlTagRegex().Replace(s, "")).Trim();

record SearchResult(string Title, string Snippet);

